const cfg = require('./.forge/config.json');
const required = [
  ['version', cfg.version],
  ['project.name', cfg.project?.name],
  ['project.prefix', cfg.project?.prefix],
  ['stack', cfg.stack ? JSON.stringify(cfg.stack) : undefined],
  ['commands', cfg.commands ? JSON.stringify(cfg.commands) : undefined],
  ['paths.engineering', cfg.paths?.engineering],
  ['paths.store', cfg.paths?.store],
  ['paths.workflows', cfg.paths?.workflows],
];
let ok = true;
for (const [key, val] of required) {
  if (!val) { console.log('MISSING:', key); ok = false; }
  else { console.log('  OK:', key, '=', val); }
}
if (ok) console.log('\nAll 8 required keys present ✓');
else { console.log('\nSome keys missing!'); process.exit(1); }
